package com.courtassistant.util.date

import android.content.Context
import java.text.SimpleDateFormat
import java.util.*

/**
 * 统一的日期格式化工具类
 * 消除项目中重复的日期格式化代码
 */
object DateUtils {

    // 日期格式常量
    private const val FORMAT_DATETIME = "yyyy-MM-dd HH:mm:ss"
    private const val FORMAT_DATE_SHORT = "yyyy-MM-dd"
    private const val FORMAT_TIME_ONLY = "HH:mm:ss"

    /**
     * 格式化日期时间为标准格式：yyyy-MM-dd HH:mm:ss
     * @param date 日期对象
     * @return 格式化后的日期时间字符串
     */
    fun formatDateTime(date: Date): String {
        return SimpleDateFormat(FORMAT_DATETIME, Locale.getDefault()).format(date)
    }

    /**
     * 格式化日期为短格式：yyyy-MM-dd
     * @param date 日期对象
     * @return 格式化后的日期字符串
     */
    fun formatDateShort(date: Date): String {
        return SimpleDateFormat(FORMAT_DATE_SHORT, Locale.getDefault()).format(date)
    }

    /**
     * 格式化时间为时分秒：HH:mm:ss
     * @param date 日期对象
     * @return 格式化后的时间字符串
     */
    fun formatTimeOnly(date: Date): String {
        return SimpleDateFormat(FORMAT_TIME_ONLY, Locale.getDefault()).format(date)
    }

    /**
     * 将时间戳转换为格式化字符串
     * @param timestamp 时间戳（毫秒）
     * @param format 格式字符串，默认为 yyyy-MM-dd HH:mm:ss
     * @return 格式化后的字符串
     */
    fun formatTimestamp(timestamp: Long, format: String = FORMAT_DATETIME): String {
        return SimpleDateFormat(format, Locale.getDefault()).format(Date(timestamp))
    }

    /**
     * 获取当前时间的格式化字符串
     * @param format 格式字符串，默认为 yyyy-MM-dd HH:mm:ss
     * @return 当前时间的格式化字符串
     */
    fun getCurrentDateTime(format: String = FORMAT_DATETIME): String {
        return SimpleDateFormat(format, Locale.getDefault()).format(Date())
    }

    /**
     * 解析日期字符串为Date对象
     * @param dateStr 日期字符串
     * @param format 格式字符串，默认为 yyyy-MM-dd HH:mm:ss
     * @return Date对象，解析失败返回null
     */
    fun parseDate(dateStr: String, format: String = FORMAT_DATETIME): Date? {
        return try {
            SimpleDateFormat(format, Locale.getDefault()).parse(dateStr)
        } catch (e: Exception) {
            null
        }
    }
}

package com.courtassistant.util.file

import android.content.Context
import android.os.Environment
import java.io.File
import java.text.DecimalFormat

/**
 * 统一的文件操作工具类
 * 提供文件创建、目录管理、文件大小格式化等功能
 */
object FileUtils {

    /**
     * 确保目录存在，不存在则创建
     * @param file 目录文件对象
     * @return 是否成功
     */
    fun ensureDir(file: File): Boolean {
        return if (!file.exists()) {
            file.mkdirs()
        } else {
            true
        }
    }

    /**
     * 格式化文件大小显示
     * @param size 文件大小（字节）
     * @return 格式化后的大小字符串（KB/MB/GB）
     */
    fun formatSize(size: Long): String {
        if (size <= 0) return "0 B"

        val units = arrayOf("B", "KB", "MB", "GB", "TB")
        var index = 0
        var fileSize = size.toDouble()

        while (fileSize >= 1024 && index < units.size - 1) {
            fileSize /= 1024
            index++
        }

        val df = DecimalFormat("#.##")
        return "${df.format(fileSize)} ${units[index]}"
    }

    /**
     * 获取文件扩展名
     * @param file 文件对象
     * @return 扩展名（包含点号），如果没有扩展名返回空字符串
     */
    fun getFileExtension(file: File): String {
        return getFileExtension(file.name)
    }

    /**
     * 从文件名获取扩展名
     * @param filename 文件名
     * @return 扩展名（包含点号），如果没有扩展名返回空字符串
     */
    fun getFileExtension(filename: String): String {
        val lastDot = filename.lastIndexOf('.')
        return if (lastDot > 0) {
            filename.substring(lastDot)
        } else {
            ""
        }
    }

    /**
     * 创建PDF输出目录
     * @param context 上下文
     * @return PDF目录文件对象
     */
    fun createPdfDirectory(context: Context): File {
        // 使用应用的专属目录
        val appDir = context.getExternalFilesDir(Environment.DIRECTORY_DOCUMENTS)
        val pdfDir = File(appDir, "CourtAssistant/PDFs")

        // 确保目录存在
        ensureDir(pdfDir)

        return pdfDir
    }

    /**
     * 检查文件是否存在
     * @param file 文件对象
     * @return 是否存在
     */
    fun fileExists(file: File): Boolean {
        return file.exists() && file.isFile
    }

    /**
     * 检查目录是否存在
     * @param dir 目录对象
     * @return 是否存在
     */
    fun dirExists(dir: File): Boolean {
        return dir.exists() && dir.isDirectory
    }

    /**
     * 删除文件
     * @param file 文件对象
     * @return 是否删除成功
     */
    fun deleteFile(file: File): Boolean {
        return file.exists() && file.delete()
    }

    /**
     * 删除目录及其内容
     * @param dir 目录对象
     * @return 是否删除成功
     */
    fun deleteDirectory(dir: File): Boolean {
        if (dir.exists()) {
            dir.listFiles()?.forEach { file ->
                if (file.isDirectory) {
                    deleteDirectory(file)
                } else {
                    file.delete()
                }
            }
            return dir.delete()
        }
        return false
    }
}

package com.courtassistant.util.ui

import android.content.Context
import android.widget.Toast

/**
 * 统一的Toast显示工具类
 * 消除项目中重复的Toast代码，提供便捷的成功、错误、信息显示方法
 */
object ToastUtils {

    private var context: Context? = null

    /**
     * 初始化Context（必须在Application类中调用）
     * @param context 上下文对象
     */
    fun init(context: Context) {
        this.context = context.applicationContext
    }

    /**
     * 显示成功消息
     * @param message 消息内容
     */
    fun showSuccess(message: String) {
        show(message, Toast.LENGTH_SHORT)
    }

    /**
     * 显示成功消息
     * @param resourceId 资源ID
     */
    fun showSuccess(resourceId: Int) {
        show(resourceId, Toast.LENGTH_SHORT)
    }

    /**
     * 显示错误消息
     * @param message 消息内容
     */
    fun showError(message: String) {
        show(message, Toast.LENGTH_LONG)
    }

    /**
     * 显示错误消息
     * @param resourceId 资源ID
     */
    fun showError(resourceId: Int) {
        show(resourceId, Toast.LENGTH_LONG)
    }

    /**
     * 显示信息消息
     * @param message 消息内容
     */
    fun showInfo(message: String) {
        show(message, Toast.LENGTH_SHORT)
    }

    /**
     * 显示信息消息
     * @param resourceId 资源ID
     */
    fun showInfo(resourceId: Int) {
        show(resourceId, Toast.LENGTH_SHORT)
    }

    /**
     * 显示警告消息
     * @param message 消息内容
     */
    fun showWarning(message: String) {
        show(message, Toast.LENGTH_SHORT)
    }

    /**
     * 显示警告消息
     * @param resourceId 资源ID
     */
    fun showWarning(resourceId: Int) {
        show(resourceId, Toast.LENGTH_SHORT)
    }

    /**
     * 内部Toast显示方法
     * @param message 消息内容
     * @param duration 显示时长
     */
    private fun show(message: String, duration: Int) {
        context?.let {
            Toast.makeText(it, message, duration).show()
        }
    }

    /**
     * 内部Toast显示方法
     * @param resourceId 资源ID
     * @param duration 显示时长
     */
    private fun show(resourceId: Int, duration: Int) {
        context?.let {
            Toast.makeText(it, resourceId, duration).show()
        }
    }

    /**
     * 检查是否已初始化
     * @return 是否已初始化
     */
    fun isInitialized(): Boolean {
        return context != null
    }
}

package com.courtassistant.util.ui

import android.content.Context
import android.net.Uri
import android.os.Environment
import androidx.core.content.FileProvider
import java.io.File

/**
 * 统一的URI处理工具类
 * 消除FileProvider相关的重复代码，提供安全的文件URI创建方法
 */
object UriUtils {

    /**
     * 通过FileProvider创建文件URI
     * @param context 上下文
     * @param file 文件对象
     * @return 文件的URI
     */
    fun createFileUri(context: Context, file: File): Uri {
        return FileProvider.getUriForFile(
            context,
            "${context.packageName}.fileprovider",
            file
        )
    }

    /**
     * 创建ContentProvider URI
     * @param context 上下文
     * @param path 文件路径
     * @return URI
     */
    fun createProviderUri(context: Context, path: String): Uri {
        return FileProvider.getUriForFile(
            context,
            "${context.packageName}.fileprovider",
            File(path)
        )
    }

    /**
     * 创建外部存储文件的URI
     * @param context 上下文
     * @param relativePath 相对路径（相对于外部存储目录）
     * @return URI
     */
    fun createExternalFileUri(context: Context, relativePath: String): Uri? {
        val file = File(Environment.getExternalStorageDirectory(), relativePath)
        return try {
            createFileUri(context, file)
        } catch (e: Exception) {
            null
        }
    }

    /**
     * 创建缓存文件的URI
     * @param context 上下文
     * @param fileName 文件名
     * @return URI
     */
    fun createCacheFileUri(context: Context, fileName: String): Uri {
        val cacheDir = context.cacheDir
        val file = File(cacheDir, fileName)
        return createFileUri(context, file)
    }

    /**
     * 创建临时文件的URI
     * @param context 上下文
     * @param prefix 文件名前缀
     * @param extension 文件扩展名（包含点号）
     * @return URI
     */
    fun createTempFileUri(context: Context, prefix: String, extension: String): Uri {
        val tempDir = File(context.cacheDir, "temp")
        if (!tempDir.exists()) {
            tempDir.mkdirs()
        }
        val file = File.createTempFile(prefix, extension, tempDir)
        return createFileUri(context, file)
    }

    /**
     * 检查URI是否有效
     * @param uri URI对象
     * @return 是否有效
     */
    fun isValidUri(uri: Uri?): Boolean {
        return uri != null && uri.toString().isNotEmpty()
    }

    /**
     * 获取URI的文件名
     * @param uri URI对象
     * @return 文件名，如果无法获取返回null
     */
    fun getFileNameFromUri(uri: Uri?): String? {
        return uri?.lastPathSegment?.split(File.separatorChar)?.lastOrNull()
    }

    /**
     * 从路径创建URI
     * @param context 上下文
     * @param filePath 文件路径
     * @return URI，如果文件不存在返回null
     */
    fun fromFilePath(context: Context, filePath: String): Uri? {
        val file = File(filePath)
        return if (file.exists()) {
            createFileUri(context, file)
        } else {
            null
        }
    }
}

package com.courtassistant.util.log

import android.util.Log

/**
 * 统一的日志管理工具类
 * 提供统一的日志输出方法，自动添加TAG前缀，方便调试和问题追踪
 */
object Logger {

    // 默认TAG
    private const val DEFAULT_TAG = "CourtAssistant"

    /**
     * 调试日志（级别最低）
     * @param tag 标签
     * @param message 消息内容
     * @param throwable 异常信息
     */
    fun d(tag: String = DEFAULT_TAG, message: String, throwable: Throwable? = null) {
        if (BuildConfig.DEBUG) {
            if (throwable != null) {
                Log.d(tag, message, throwable)
            } else {
                Log.d(tag, message)
            }
        }
    }

    /**
     * 调试日志（使用类名作为TAG）
     * @param message 消息内容
     * @param throwable 异常信息
     */
    inline fun d(message: String, noinline throwable: (() -> Throwable)? = null) {
        val className = Throwable().stackTrace[1].className.split(".").last()
        val exception = throwable?.invoke()
        d(className, message, exception)
    }

    /**
     * 错误日志（级别最高）
     * @param tag 标签
     * @param message 消息内容
     * @param throwable 异常信息
     */
    fun e(tag: String = DEFAULT_TAG, message: String, throwable: Throwable? = null) {
        if (BuildConfig.DEBUG) {
            if (throwable != null) {
                Log.e(tag, message, throwable)
            } else {
                Log.e(tag, message)
            }
        }
    }

    /**
     * 错误日志（使用类名作为TAG）
     * @param message 消息内容
     * @param throwable 异常信息
     */
    inline fun e(message: String, noinline throwable: (() -> Throwable)? = null) {
        val className = Throwable().stackTrace[1].className.split(".").last()
        val exception = throwable?.invoke()
        e(className, message, exception)
    }

    /**
     * 信息日志
     * @param tag 标签
     * @param message 消息内容
     * @param throwable 异常信息
     */
    fun i(tag: String = DEFAULT_TAG, message: String, throwable: Throwable? = null) {
        if (BuildConfig.DEBUG) {
            if (throwable != null) {
                Log.i(tag, message, throwable)
            } else {
                Log.i(tag, message)
            }
        }
    }

    /**
     * 信息日志（使用类名作为TAG）
     * @param message 消息内容
     * @param throwable 异常信息
     */
    inline fun i(message: String, noinline throwable: (() -> Throwable)? = null) {
        val className = Throwable().stackTrace[1].className.split(".").last()
        val exception = throwable?.invoke()
        i(className, message, exception)
    }

    /**
     * 警告日志
     * @param tag 标签
     * @param message 消息内容
     * @param throwable 异常信息
     */
    fun w(tag: String = DEFAULT_TAG, message: String, throwable: Throwable? = null) {
        if (BuildConfig.DEBUG) {
            if (throwable != null) {
                Log.w(tag, message, throwable)
            } else {
                Log.w(tag, message)
            }
        }
    }

    /**
     * 警告日志（使用类名作为TAG）
     * @param message 消息内容
     * @param throwable 异常信息
     */
    inline fun w(message: String, noinline throwable: (() -> Throwable)? = null) {
        val className = Throwable().stackTrace[1].className.split(".").last()
        val exception = throwable?.invoke()
        w(className, message, exception)
    }

    /**
     * 详细日志（介于调试和信息之间）
     * @param tag 标签
     * @param message 消息内容
     * @param throwable 异常信息
     */
    fun v(tag: String = DEFAULT_TAG, message: String, throwable: Throwable? = null) {
        if (BuildConfig.DEBUG) {
            if (throwable != null) {
                Log.v(tag, message, throwable)
            } else {
                Log.v(tag, message)
            }
        }
    }

    /**
     * 警告日志（只显示一次）
     * @param tag 标签
     * @param message 消息内容
     */
    fun wOnce(tag: String = DEFAULT_TAG, message: String) {
        // 使用静态Set来记录已显示的警告，避免重复显示
        synchronized(this) {
            val shownWarnings = HashSet<String>()
            val uniqueKey = "$tag-$message"
            if (!shownWarnings.contains(uniqueKey)) {
                shownWarnings.add(uniqueKey)
                w(tag, message)
            }
        }
    }

    /**
     * 输出方法调用日志（用于调试）
     */
    fun logMethodEntry(className: String = DEFAULT_TAG, methodName: String) {
        d(className, "🔍 Entry: $methodName()")
    }

    /**
     * 输出方法退出日志（用于调试）
     */
    fun logMethodExit(className: String = DEFAULT_TAG, methodName: String) {
        d(className, "✅ Exit: $methodName()")
    }

    /**
     * 输入异常日志（包含调用栈）
     * @param tag 标签
     * @param message 消息内容
     * @param throwable 异常信息
     */
    fun logError(tag: String = DEFAULT_TAG, message: String, throwable: Throwable? = null) {
        e(tag, message, throwable)
    }

    /**
     * 设置日志级别（用于生产环境）
     * @param level 日志级别
     */
    fun setLogLevel(level: Int) {
        // 可以在这里实现日志级别控制
        // Log.setLevel(level)
    }
}

