        var fileSize = size.toDouble()

        while (fileSize >= 1024 && index < units.size - 1) {
            fileSize /= 1024
            index++
        }

        val df = DecimalFormat("#.##")
        return "${df.format(fileSize)} ${units[index]}"
    }

